CREATE OR REPLACE FUNCTION fpa_get_prin_int_group_code (as_receipt_no char , as_status char , as_loan_group_code char , as_receive_status char) RETURNS bigint AS $body$
DECLARE

  adc_total bigint;
  adc_prin bigint;
  adc_int bigint;
  adc_item_amount bigint;
  adc_balance bigint;
  adc_return bigint;

BEGIN
  case trim(both as_receive_status)
	when '0' then
    begin
      select	sum( sc_com_m_receipt_item.principal_amount ) ,
            sum( sc_com_m_receipt_item.interest_amount ) ,
            sum( sc_com_m_receipt_item.item_amount ) ,
            sum( sc_com_m_receipt_item.balance )
      into STRICT adc_prin , adc_int , adc_item_amount , adc_balance
      from sc_com_m_receipt ,
            sc_com_m_receipt_item ,
            sc_lon_m_rule
      where	sc_com_m_receipt.receipt_no = sc_com_m_receipt_item.receipt_no
      and		sc_com_m_receipt_item.loan_type = sc_lon_m_rule.loan_type
      and		sc_com_m_receipt.receipt_no = as_receipt_no
      and		sc_lon_m_rule.loan_group_code = as_loan_group_code
      and		sc_com_m_receipt.receipt_status = as_receive_status	;
      exception when others then CALL spa_dberror('E:301 select error : ('||trim(both as_receipt_no)||')');
    end;
	when '1' then
    begin
      select	sum( sc_com_m_receipt_item.principal_amount ) ,
            sum( sc_com_m_receipt_item.interest_amount ) ,
            sum( sc_com_m_receipt_item.item_amount ) ,
            sum( sc_com_m_receipt_item.balance )
      into STRICT adc_prin , adc_int , adc_item_amount , adc_balance
      from sc_com_m_receipt ,
            sc_com_m_receipt_item ,
            sc_lon_m_rule
      where	sc_com_m_receipt.receipt_no = sc_com_m_receipt_item.receipt_no
      and		sc_com_m_receipt_item.loan_type = sc_lon_m_rule.loan_type
      and		sc_com_m_receipt.receipt_no = as_receipt_no
      and		sc_lon_m_rule.loan_group_code = as_loan_group_code
      and		sc_com_m_receipt.receipt_status = as_receive_status	;
      exception when others then CALL spa_dberror('E:302 select error : ('||trim(both as_receipt_no)||')');
    end;
	when 'all' then
    begin
      select	sum( sc_com_m_receipt_item.principal_amount ) ,
            sum( sc_com_m_receipt_item.interest_amount ) ,
            sum( sc_com_m_receipt_item.item_amount ) ,
            sum( sc_com_m_receipt_item.balance )
      into STRICT adc_prin , adc_int , adc_item_amount , adc_balance
      from sc_com_m_receipt ,
            sc_com_m_receipt_item ,
            sc_lon_m_rule
      where	sc_com_m_receipt.receipt_no = sc_com_m_receipt_item.receipt_no
      and		sc_com_m_receipt_item.loan_type = sc_lon_m_rule.loan_type
      and		sc_com_m_receipt.receipt_no =  as_receipt_no
      and		sc_lon_m_rule.loan_group_code =  as_loan_group_code;
      exception when others then CALL spa_dberror('E:303 select error : ('||trim(both as_receipt_no)||')');
    end;
  else
    adc_return := 0;
  end case;

    adc_total := adc_prin + adc_int;

  case upper(as_status)
    when 'PRIN' then  -- ต้น
      adc_return := adc_prin;
    when 'INT' then  -- ยอด
      adc_return := adc_int;
    when 'ALL' then  -- ต้น + ดอก
      adc_return := adc_total;
    when 'ITEM' then  -- ยอดชำระ
      adc_return := adc_item_amount;
    when 'BALANCE' then  -- หนี้คงเหลือ
      adc_return := adc_balance;
    else
      adc_return := 0;
  end case;

  return coalesce(adc_return,0);
exception when others then CALL spa_dberror('fpa_get_prin_int_group_code');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
